class Command {
  constructor(name = '') {
    this._name = name;
    this._description = '';
    this._version = '';
    this._commands = [];
    this._action = null;
  }

  name(value) { this._name = value; return this; }
  description(value) { this._description = value; return this; }
  version(value) { this._version = value; return this; }
  option() { return this; }

  command(name) {
    const child = new Command(name.split(' ')[0]);
    this._commands.push(child);
    return child;
  }

  action(fn) { this._action = fn; return this; }

  async parseAsync(argv) {
    const args = argv.slice(2);
    const first = args[0];
    if (!first || first === '--help' || first === '-h') {
      this._printHelp();
      return this;
    }
    if (first === '--version' || first === '-V') {
      process.stdout.write(`${this._version}\n`);
      return this;
    }
    const command = this._commands.find((entry) => entry._name === first);
    if (!command) {
      process.stderr.write(`Unknown command: ${first}\n`);
      process.exitCode = 1;
      return this;
    }
    if (args[1] === '--help' || args[1] === '-h') {
      this._printCommandHelp(command);
      return this;
    }
    await command._action?.(...args.slice(1));
    return this;
  }

  _printHelp() {
    process.stdout.write(`${this._name} ${this._version}\n${this._description}\n\nCommands:\n`);
    for (const command of this._commands) {
      process.stdout.write(`  ${command._name.padEnd(10)} ${command._description}\n`);
    }
  }

  _printCommandHelp(command) {
    process.stdout.write(`${command._name}\n${command._description}\n`);
  }
}

export { Command };
